const item = $input.first();
const headers = item.json.headers;

// Azure returns operation URL in header
const operationUrl = headers['operation-location'] || headers['Operation-Location'];

if (!operationUrl) {
  throw new Error('No operation-location header found in Azure response');
}

return [{
  json: {
    operationUrl: operationUrl,
    section: item.json.section,
    focusArea: item.json.focusArea
  }
}];

// Extract only word text from Azure OCR response
const azureResponse = $input.item.json.body;

const allWords = [];

azureResponse.analyzeResult.readResults.forEach(page => {
  page.lines.forEach(line => {
    line.words.forEach(word => {
      allWords.push(word.text);
    });
  });
});

return [{
  json: {
    words: allWords,
    fullText: allWords.join(' ')
  }
}];

// Parse Gemini response and extract errors
const item = $input.first().json;

let rawText = "";

// Extract text from various possible structures
if (item.content?.parts?.[0]?.text) {
  rawText = item.content.parts[0].text;
} else if (item.candidates?.[0]?.content?.parts?.[0]?.text) {
  rawText = item.candidates[0].content.parts[0].text;
} else if (typeof item === 'string') {
  rawText = item;
} else {
  rawText = JSON.stringify(item);
}

// Clean markdown fences
rawText = rawText.replace(/```json|```/g, '').trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  console.error('Parse error:', e.message);
  return [{
    json: {
      error: 'Failed to parse Gemini output',
      raw_preview: rawText.substring(0, 500)
    }
  }];
}

const errors = parsed.errors_detected || [];
const summary = parsed.summary || {};
const metadata = parsed.image_metadata || {};

return [{
  json: {
    parsed_response: parsed,
    errors: errors,
    summary: summary,
    metadata: metadata,
    total_errors: errors.length
  }
}];

// Try to get execution ID from the Generate Execution ID node
let executionId;
try {
  executionId = $('Generate Execution ID').first().json.executionId;
} catch (e) {
  // Fallback: generate one here if the node didn't execute
  const crypto = require('crypto');
  executionId = crypto.randomUUID();
  console.log('Generated fallback execution ID:', executionId);
}

const crypto = require('crypto');
const inputItem = $input.first().json;

// Get errors from parsed_response
const wordErrors = inputItem.parsed_response?.word_level_errors || [];
const paragraphErrors = inputItem.parsed_response?.paragraph_level_errors || [];

// Combine all errors
const allErrors = [
  ...wordErrors.map(error => ({ ...error, error_level: 'word' })),
  ...paragraphErrors.map(error => ({ ...error, error_level: 'paragraph' }))
];

// If no errors, return empty array
if (allErrors.length === 0) {
  return [];
}

// Map fields to match Supabase column names
return allErrors.map((error) => ({
  json: {
    executionId: executionId,
    error_id: crypto.randomUUID(),
    found_text: error.found_text || '',
    error_type: error.error_type || '',
    correction: error.corrected_text || '', // Map corrected_text → correction
    issue_description: error.explanation || '', // Map explanation → issue_description
    panel_zone: error.location || '', // Map location → panel_zone
    confidence: error.confidence || '', // Add confidence if available
    error_level: error.error_level || '', // Add error_level
    severity: error.severity || '', // Add severity
    coordinates: '' // Empty for now, add if you have coordinate data
  }
}));
